     1→import { create } from 'zustand';
     2→import { friendlyErrorMessage } from '@/launcher/errors';
     3→import type {
     4→  ConsoleEvent,
     5→  ContentKind,
     6→  DeviceCodeStart,
     7→  DownloadProgress,
     8→  Instance,
     9→  JavaRuntime,
    10→  LauncherAccount,
    11→  LauncherSettings,
    12→  MarketplaceProject,
    13→  MarketplaceSearchQuery,
    14→  NotificationItem,
    15→  PageId,
    16→  ProcessState,
    17→  VersionCatalog
    18→} from '@/types/launcher';
    19→
    20→export type { PageId };
    21→
    22→interface LauncherState {
    23→  activePage: PageId;
    24→  settings?: LauncherSettings;
    25→  accounts: LauncherAccount[];
    26→  instances: Instance[];
    27→  versions: string[];
    28→  versionCatalog: VersionCatalog;
    29→  javaRuntimes: JavaRuntime[];
    30→  downloads: DownloadProgress[];
    31→  consoleEvents: ConsoleEvent[];
    32→  processStates: Record<string, ProcessState>;
    33→  notifications: NotificationItem[];
    34→  librarySearch: string;
    35→  librarySearchNonce: number;
    36→  selectedInstanceId?: string;
    37→  selectedAccountId?: string;
    38→  loading: boolean;
    39→  busyLabel?: string;
    40→  error?: string;
    41→  setActivePage(page: PageId): void;
    42→  setLibrarySearch(query: string): void;
    43→  triggerLibrarySearch(): void;
    44→  bootstrap(): Promise<void>;
    45→  refresh(): Promise<void>;
    46→  createInstance(input?: Partial<Instance>): Promise<void>;
    47→  updateInstance(id: string, input: Partial<Instance>): Promise<void>;
    48→  removeInstance(id: string): Promise<void>;
    49→  duplicateInstance(id: string): Promise<void>;
    50→  setSelectedInstance(id: string): void;
    51→  setSelectedAccount(id: string): Promise<void>;
    52→  launchSelected(): Promise<void>;
    53→  stopGame(instanceId: string): Promise<void>;
    54→  scanJava(): Promise<void>;
    55→  saveSettings(input: Partial<LauncherSettings>): Promise<void>;
    56→  addOfflineAccount(username: string): Promise<void>;
    57→  startMicrosoftLogin(): Promise<DeviceCodeStart>;
    58→  completeMicrosoftLogin(): Promise<void>;
    59→  searchMarketplace(query: MarketplaceSearchQuery): Promise<MarketplaceProject[]>;
    60→  installProject(project: MarketplaceProject, instanceId: string): Promise<void>;
    61→  listContent(instanceId: string, kind: ContentKind): Promise<unknown>;
    62→}
    63→
    64→let _bootstrapped = false;
    65→
    66→export const useLauncherStore = create<LauncherState>((set, get) => ({
    67→  activePage: 'home',
    68→  accounts: [],
    69→  instances: [],
    70→  versions: [],
    71→  versionCatalog: { releases: [], snapshots: [], all: [] },
    72→  javaRuntimes: [],
    73→  downloads: [],
    74→  consoleEvents: [],
    75→  processStates: {},
    76→  notifications: [],
    77→  librarySearch: '',
    78→  librarySearchNonce: 0,
    79→  loading: true,
    80→  setActivePage: (page) => set({ activePage: page }),
    81→  setLibrarySearch: (query) => set({ librarySearch: query }),
    82→  triggerLibrarySearch: () => set((state) => ({ librarySearchNonce: state.librarySearchNonce + 1 })),
    83→  setSelectedInstance: (id) => set({ selectedInstanceId: id }),
    84→  bootstrap: async () => {
    85→    if (_bootstrapped) return;
    86→    _bootstrapped = true;
    87→    const unsubs = [
    88→      window.dawn.events.onDownloadProgress((progress) => {
    89→        set((state) => ({
    90→          downloads: [progress, ...state.downloads.filter((item) => item.id !== progress.id)].slice(0, 80)
    91→        }));
    92→      }),
    93→      window.dawn.events.onConsole((event) => {
    94→        set((state) => ({ consoleEvents: [...state.consoleEvents, event].slice(-400) }));
    95→      }),
    96→      window.dawn.events.onNotification((event) => {
    97→        set((state) => ({ notifications: [event, ...state.notifications].slice(0, 8) }));
    98→      }),
    99→      window.dawn.events.onProcessState(({ instanceId, state }) => {
   100→        set((current) => ({
   101→          processStates: { ...current.processStates, [instanceId]: state }
   102→        }));
   103→      })
   104→    ];
   105→    window.addEventListener('beforeunload', () => unsubs.forEach((unsubscribe) => unsubscribe()), { once: true });
   106→    await get().refresh();
   107→  },
   108→  refresh: async () => {
   109→    set({ loading: true, error: undefined });
   110→    try {
   111→      const [settings, accounts, instances, downloads, processStates] = await Promise.all([
   112→        window.dawn.settings.get(),
   113→        window.dawn.accounts.list(),
   114→        window.dawn.instances.list(),
   115→        window.dawn.downloads.list(),
   116→        window.dawn.minecraft.getProcessStates()
   117→      ]);
   118→      set({
   119→        settings,
   120→        accounts,
   121→        instances,
   122→        downloads,
   123→        processStates,
   124→        selectedAccountId: accounts.find((account) => account.selected)?.id ?? accounts[0]?.id,
   125→        selectedInstanceId: get().selectedInstanceId ?? instances[0]?.id,
   126→        loading: false
   127→      });
   128→      void window.dawn.minecraft.listVersionCatalog().then((versionCatalog) => set({ versionCatalog, versions: versionCatalog.all }));
   129→      void get().scanJava();
   130→    } catch (error) {
   131→      set({ loading: false, error: friendlyErrorMessage(error) });
   132→    }
   133→  },
   134→  createInstance: async (input = {}) => {
   135→    set({ busyLabel: 'Creating instance', error: undefined });
   136→    try {
   137→      const instance = await window.dawn.instances.create(input);
   138→      set((state) => ({ instances: [instance, ...state.instances], selectedInstanceId: instance.id, busyLabel: undefined }));
   139→    } catch (error) {
   140→      set({ busyLabel: undefined, error: friendlyErrorMessage(error) });
   141→      throw error;
   142→    }
   143→  },
   144→  updateInstance: async (id, input) => {
   145→    const updated = await window.dawn.instances.update(id, input);
   146→    set((state) => ({ instances: state.instances.map((item) => (item.id === id ? updated : item)) }));
   147→  },
   148→  removeInstance: async (id) => {
   149→    await window.dawn.instances.remove(id);
   150→    set((state) => {
   151→      const instances = state.instances.filter((item) => item.id !== id);
   152→      return { instances, selectedInstanceId: instances[0]?.id };
   153→    });
   154→  },
   155→  duplicateInstance: async (id) => {
   156→    const instance = await window.dawn.instances.duplicate(id);
   157→    set((state) => ({ instances: [instance, ...state.instances], selectedInstanceId: instance.id }));
   158→  },
   159→  setSelectedAccount: async (id) => {
   160→    const accounts = await window.dawn.accounts.select(id);
   161→    set({ accounts, selectedAccountId: id });
   162→  },
   163→  launchSelected: async () => {
   164→    const { selectedInstanceId, selectedAccountId } = get();
   165→    if (!selectedInstanceId || !selectedAccountId) {
   166→      set({ error: 'Choose an instance and account before launching.' });
   167→      return;
   168→    }
   169→    set({ busyLabel: 'Launching Minecraft', activePage: 'console', error: undefined });
   170→    try {
   171→      await window.dawn.minecraft.launch({ instanceId: selectedInstanceId, accountId: selectedAccountId });
   172→      await get().refresh();
   173→    } catch (error) {
   174→      const message = friendlyErrorMessage(error);
   175→      set((state) => ({
   176→        error: message,
   177→        consoleEvents: [
   178→          ...state.consoleEvents,
   179→          {
   180→            instanceId: selectedInstanceId,
   181→            level: 'error' as const,
   182→            message,
   183→            time: Date.now()
   184→          }
   185→        ].slice(-400)
   186→      }));
   187→    } finally {
   188→      set({ busyLabel: undefined });
   189→    }
   190→  },
   191→  stopGame: async (instanceId) => {
   192→    set({ busyLabel: 'Stopping Minecraft' });
   193→    try {
   194→      await window.dawn.minecraft.stop(instanceId);
   195→    } catch (error) {
   196→      set({ error: friendlyErrorMessage(error) });
   197→    } finally {
   198→      set({ busyLabel: undefined });
   199→    }
   200→  },
   201→  scanJava: async () => {
   202→    const javaRuntimes = await window.dawn.minecraft.scanJava();
   203→    set({ javaRuntimes });
   204→  },
   205→  saveSettings: async (input) => {
   206→    const settings = await window.dawn.settings.update(input);
   207→    set({ settings });
   208→  },
   209→  addOfflineAccount: async (username) => {
   210→    const account = await window.dawn.accounts.addOffline(username);
   211→    set((state) => ({
   212→      accounts: [...state.accounts.map((item) => ({ ...item, selected: false })), account],
   213→      selectedAccountId: account.id
   214→    }));
   215→  },
   216→  startMicrosoftLogin: async () => {
   217→    set({ busyLabel: 'Starting Microsoft login', error: undefined });
   218→    try {
   219→      return await window.dawn.accounts.microsoftStart();
   220→    } catch (error) {
   221→      set({ error: friendlyErrorMessage(error) });
   222→      throw error;
   223→    } finally {
   224→      set({ busyLabel: undefined });
   225→    }
   226→  },
   227→  completeMicrosoftLogin: async () => {
   228→    set({ busyLabel: 'Completing Microsoft login', error: undefined });
   229→    try {
   230→      const account = await window.dawn.accounts.microsoftComplete();
   231→      set((state) => ({
   232→        accounts: [...state.accounts.map((item) => ({ ...item, selected: false })), account],
   233→        selectedAccountId: account.id
   234→      }));
   235→    } catch (error) {
   236→      set({ error: friendlyErrorMessage(error) });
   237→      throw error;
   238→    } finally {
   239→      set({ busyLabel: undefined });
   240→    }
   241→  },
   242→  searchMarketplace: (query) => window.dawn.marketplace.search(query),
   243→  installProject: async (project, instanceId) => {
   244→    set({ busyLabel: `Installing ${project.title}`, error: undefined });
   245→    try {
   246→      await window.dawn.marketplace.install(project, instanceId);
   247→      await get().refresh();
   248→    } catch (error) {
   249→      set({ error: friendlyErrorMessage(error) });
   250→      throw error;
   251→    } finally {
   252→      set({ busyLabel: undefined });
   253→    }
   254→  },
   255→  listContent: (instanceId, kind) => window.dawn.content.list(instanceId, kind)
   256→}));
