    63→async function saveWindowBounds(): Promise<void> {
    64→  if (!mainWindow || mainWindow.isMaximized() || mainWindow.isMinimized()) {
    65→    return;
    66→  }
    67→
    68→  const [width, height] = mainWindow.getSize();
    69→  await database.mutate((draft) => {
    70→    draft.settings.windowWidth = width;
    71→    draft.settings.windowHeight = height;
    72→  });
    73→}
