    75→async function createWindow(settings?: LauncherSettings): Promise<void> {
    76→  const useCustomChrome = process.platform !== 'darwin';
    77→  const width = Math.max(1040, settings?.windowWidth ?? 1280);
    78→  const height = Math.max(680, settings?.windowHeight ?? 800);
