    97→
    98→  mainWindow.on('maximize', () => mainWindow?.webContents.send('window:maximized', true));
    99→  mainWindow.on('unmaximize', () => mainWindow?.webContents.send('window:maximized', false));
   100→  mainWindow.on('resize', () => {
   101→    void saveWindowBounds();
   102→  });
   103→  mainWindow.on('close', () => {
   104→    void saveWindowBounds();
   105→  });
   106→
   107→  mainWindow.once('ready-to-show', () => {
   108→    mainWindow?.show();
