   150→function simulateLaunch(instanceId: string) {
   151→  const inst = instances.find((i) => i.id === instanceId);
   152→  const instName = inst?.name ?? instanceId;
   153→  const timers: ReturnType<typeof setTimeout>[] = [];
   154→  activeTimers.set(instanceId, timers);
   155→
   156→  emitProcessState(instanceId, 'preparing');
   157→  emitConsole(instanceId, 'info', `Launching "${instName}" (${inst?.gameVersion ?? '?'} / ${inst?.loader ?? 'vanilla'})…`);
   158→
   159→  for (const [delay, level, msg] of launchLogScript) {
   160→    timers.push(setTimeout(() => emitConsole(instanceId, level, msg), delay));
   161→  }
   162→
   163→  timers.push(setTimeout(() => emitProcessState(instanceId, 'launching'), 800));
   164→  timers.push(setTimeout(() => emitProcessState(instanceId, 'running'), 2400));
   165→  timers.push(setTimeout(() => {
   166→    emitProcessState(instanceId, 'exited');
   167→    activeTimers.delete(instanceId);
   168→  }, 12000));
   169→}
