    27→  async write(next: LauncherDatabaseShape): Promise<void> {
    28→    await mkdir(dirname(this.filePath), { recursive: true });
    29→    const tempPath = `${this.filePath}.tmp`;
    30→    await writeFile(tempPath, `${JSON.stringify(next, null, 2)}\n`, 'utf8');
    31→    await rename(tempPath, this.filePath);
    32→    this.data = structuredClone(next);
    33→  }
