   217→
   218→    if (session.child?.pid) {
   219→      await killProcessTree(session.child).catch((error) => {
   220→        void this.logger?.warn('launch', 'Failed to kill process tree', {
   221→          instanceId,
   222→          error: error instanceof Error ? error.message : String(error)
   223→        });
   224→      });
   225→    }
   226→
   227→    this.sessions.delete(instanceId);
   228→    this.setState(instanceId, 'stopped');
   229→    this.emit(instanceId, 'info', 'Minecraft stopped');
   230→    await this.logger?.info('launch', 'Stopped by user', { instanceId });
