   256→    }
   257→    if (runtime.major < requiredMajor) {
   258→      throw new Error(`Java ${requiredMajor}+ is required for Minecraft ${gameVersion}. Selected Java is ${runtime.major}.`);
   259→    }
   260→    return runtime;
   261→  }
