import { mkdir, readFile, rename, writeFile } from 'node:fs/promises';
import { dirname } from 'node:path';
import type { LauncherDatabaseShape } from '@/types/launcher';
import { createDefaultDatabase } from './defaults';

export class JsonDatabase {
  private data?: LauncherDatabaseShape;

  constructor(private readonly filePath: string) {}

  async read(): Promise<LauncherDatabaseShape> {
    if (this.data) {
      return structuredClone(this.data);
    }

    try {
      const raw = await readFile(this.filePath, 'utf8');
      this.data = this.mergeDefaults(JSON.parse(raw) as Partial<LauncherDatabaseShape>);
    } catch {
      this.data = createDefaultDatabase();
      await this.write(this.data);
    }

    return structuredClone(this.data);
  }

  async write(next: LauncherDatabaseShape): Promise<void> {
    await mkdir(dirname(this.filePath), { recursive: true });
    const tempPath = `${this.filePath}.tmp`;
    await writeFile(tempPath, `${JSON.stringify(next, null, 2)}\n`, 'utf8');
    await rename(tempPath, this.filePath);
    this.data = structuredClone(next);
  }

  async mutate<T>(mutator: (draft: LauncherDatabaseShape) => T | Promise<T>): Promise<T> {
    const draft = await this.read();
    const result = await mutator(draft);
    await this.write(draft);
    return result;
  }

  private mergeDefaults(input: Partial<LauncherDatabaseShape>): LauncherDatabaseShape {
    const defaults = createDefaultDatabase();

    return {
      settings: { ...defaults.settings, ...input.settings },
      accounts: input.accounts ?? defaults.accounts,
      instances: input.instances ?? defaults.instances,
      resourceOrder: input.resourceOrder ?? defaults.resourceOrder,
      shaderPresets: input.shaderPresets ?? defaults.shaderPresets,
      plugins: input.plugins ?? defaults.plugins,
      notifications: input.notifications ?? defaults.notifications,
      launchHistory: input.launchHistory ?? defaults.launchHistory
    };
  }
}

import { execFile, spawn, type ChildProcess } from 'node:child_process';
import { promisify } from 'node:util';
import { nanoid } from 'nanoid';
import type { ConsoleEvent, Instance, LaunchHistoryEntry, LaunchRequest, LaunchResult, LauncherAccount, ProcessState } from '@/types/launcher';
import { AccountService } from '@/launcher/AccountService';
import { friendlyErrorMessage } from '@/launcher/errors';
import { JsonDatabase } from '@/launcher/JsonDatabase';
import { InstanceService } from '@/launcher/InstanceService';
import { validateInstanceBeforeLaunch } from '@/launcher/InstanceValidation';
import { JavaService } from '@/launcher/JavaService';
import type { Logger } from '@/launcher/Logger';
import { LoaderService } from './LoaderService';
import { VersionService } from './VersionService';

const execFileAsync = promisify(execFile);

const MAX_HISTORY_ENTRIES = 500;

interface InstanceSession {
  child?: ChildProcess;
  state: ProcessState;
  abort: AbortController;
  historyId?: string;
  launchedAt?: number;
}

export type ProcessStateListener = (instanceId: string, state: ProcessState) => void;

export class MinecraftService {
  private readonly sessions = new Map<string, InstanceSession>();

  constructor(
    private readonly database: JsonDatabase,
    private readonly versions: VersionService,
    private readonly loaders: LoaderService,
    private readonly java: JavaService,
    private readonly instances: InstanceService,
    private readonly accounts: AccountService,
    private readonly onConsole: (event: ConsoleEvent) => void,
    private readonly onProcessState: ProcessStateListener,
    private readonly logger?: Logger
  ) {}

  listVersions(): Promise<string[]> {
    return this.versions.listVersions();
  }

  listVersionCatalog() {
    return this.versions.listVersionCatalog();
  }

  scanJava() {
    return this.database.read().then(({ settings }) => this.java.scan(settings));
  }

  getProcessState(instanceId: string): ProcessState {
    return this.sessions.get(instanceId)?.state ?? 'idle';
  }

  getProcessStates(): Record<string, ProcessState> {
    const states: Record<string, ProcessState> = {};
    for (const [instanceId, session] of this.sessions) {
      states[instanceId] = session.state;
    }
    return states;
  }

  async installLoader(instanceId: string): Promise<Instance> {
    const data = await this.database.read();
    const instance = data.instances.find((item) => item.id === instanceId);
    if (!instance) {
      throw new Error('Instance not found.');
    }
    return this.loaders.install(instance, data.settings);
  }

  async listHistory(): Promise<LaunchHistoryEntry[]> {
    const data = await this.database.read();
    return [...(data.launchHistory ?? [])].reverse();
  }

  async clearHistory(): Promise<void> {
    await this.database.mutate((draft) => {
      draft.launchHistory = [];
    });
  }

  async launch(input: LaunchRequest): Promise<LaunchResult> {
    const abort = new AbortController();
    const launchedAt = Date.now();
    const historyId = nanoid();

    this.sessions.set(input.instanceId, { state: 'preparing', abort, historyId, launchedAt });

    try {
      const data = await this.database.read();
      let instance = data.instances.find((item) => item.id === input.instanceId);
      let account = data.accounts.find((item) => item.id === input.accountId);
      if (!instance) {
        throw new Error('Instance not found.');
      }
      if (!account) {
        throw new Error('Select an account before launching.');
      }

      this.assertNotAborted(input.instanceId);
      this.setState(input.instanceId, 'preparing');
      this.emit(input.instanceId, 'info', 'Validating instance');

      if (account.kind === 'microsoft') {
        account = await this.accounts.ensureValidSession(account);
      }

      const validationIssues = await validateInstanceBeforeLaunch(instance);
      for (const issue of validationIssues) {
        this.emit(input.instanceId, issue.level, issue.message);
        if (issue.level === 'error') {
          throw new Error(issue.message);
        }
      }

      this.assertNotAborted(input.instanceId);

      if (instance.loader !== 'vanilla' && !instance.launchVersionId) {
        this.emit(input.instanceId, 'info', `Installing ${instance.loader} loader`);
        instance = await this.loaders.install(instance, data.settings);
      }

      if (!instance.launchVersionId && instance.loader !== 'vanilla') {
        throw new Error(`Failed to install ${instance.loader} loader. Please try again or use vanilla Minecraft.`);
      }

      await this.instances.ensureRoots(data.settings);
      this.emit(input.instanceId, 'info', 'Preparing instance');

      const gameVersion = await this.versions.resolveAlias(instance.gameVersion);
      const versionId = instance.launchVersionId || gameVersion;
      const requiredJavaMajor =
        (await this.versions.requiredJavaMajor(versionId, data.settings)) ?? this.java.requiredMajor(gameVersion);

      this.setState(input.instanceId, 'downloading');
      this.emit(input.instanceId, 'info', 'Downloading and verifying game files');

      const runtime = instance.javaPath
        ? await this.validateCustomJava(instance.javaPath, gameVersion, requiredJavaMajor)
        : await this.java.pick(data.settings, gameVersion, requiredJavaMajor);

      this.assertNotAborted(input.instanceId);
      this.setState(input.instanceId, 'launching');

      this.emit(input.instanceId, 'info', `Using Java ${runtime.major} at ${runtime.path}`);
      const plan = await this.versions.createLaunchPlan({
        versionId,
        instance,
        account: this.normalizeAccount(account),
        java: runtime,
        settings: data.settings
      });

      this.assertNotAborted(input.instanceId);
      this.emit(input.instanceId, 'info', `Launching ${plan.version.id}`);

      const child = spawn(plan.javaPath, plan.args, {
        cwd: plan.gameDir,
        detached: process.platform !== 'win32',
        stdio: ['ignore', 'pipe', 'pipe'],
        env: {
          ...process.env,
          APPDATA: process.env.APPDATA,
          HOME: process.env.HOME
        }
      });

      await this.waitForSpawn(child, input.instanceId);
      this.assertNotAborted(input.instanceId);

      const session = this.sessions.get(input.instanceId);
      if (session) {
        session.child = child;
      }

      this.setState(input.instanceId, 'running');
      await this.instances.markPlayed(instance.id);
      await this.logger?.info('launch', `Started ${instance.name}`, { pid: child.pid, versionId });

      const historyEntry: LaunchHistoryEntry = {
        id: historyId,
        instanceId: instance.id,
        instanceName: instance.name,
        gameVersion: instance.gameVersion,
        loader: instance.loader,
        accountId: account.id,
        accountUsername: account.username,
        launchedAt,
        state: 'running'
      };
      await this.appendHistory(historyEntry);

      child.stdout?.on('data', (chunk: Buffer) => this.emit(instance!.id, 'info', chunk.toString()));
      child.stderr?.on('data', (chunk: Buffer) => this.emit(instance!.id, 'warn', chunk.toString()));
      child.on('error', (error) => this.emit(instance!.id, 'error', error.message));
      child.on('exit', (code) => {
        const exitedAt = Date.now();
        const durationMs = exitedAt - launchedAt;
        this.sessions.delete(instance!.id);
        const state: ProcessState = code === 0 ? 'exited' : 'crashed';
        this.setState(instance!.id, state);
        this.emit(instance!.id, state === 'crashed' ? 'error' : 'info', `Minecraft ${state} with code ${code ?? 'unknown'}`);
        void this.logger?.info('launch', `Process ${state}`, { instanceId: instance!.id, code });
        void this.finalizeHistory(historyId, instance!.id, exitedAt, durationMs, code, state === 'exited' ? 'exited' : 'crashed');
        setTimeout(() => {
          if (!this.sessions.has(instance!.id)) {
            this.setState(instance!.id, 'idle');
          }
        }, 1500);
      });

      return {
        pid: child.pid ?? 0,
        instanceId: instance.id,
        state: 'running'
      };
    } catch (error) {
      const aborted =
        error instanceof Error &&
        (error.name === 'AbortError' || this.sessions.get(input.instanceId)?.abort.signal.aborted);
      if (aborted) {
        const exitedAt = Date.now();
        const durationMs = exitedAt - launchedAt;
        this.setState(input.instanceId, 'stopped');
        void this.finalizeHistory(historyId, input.instanceId, exitedAt, durationMs, null, 'stopped');
        setTimeout(() => this.setState(input.instanceId, 'idle'), 1000);
        return { pid: 0, instanceId: input.instanceId, state: 'stopped' };
      }

      const message = friendlyErrorMessage(error);
      this.sessions.delete(input.instanceId);
      this.setState(input.instanceId, 'idle');
      this.emit(input.instanceId, 'error', message);
      await this.logger?.error('launch', message, { instanceId: input.instanceId });
      throw new Error(message);
    }
  }

  async stop(instanceId: string): Promise<void> {
    const session = this.sessions.get(instanceId);
    if (!session) {
      this.setState(instanceId, 'idle');
      return;
    }

    this.setState(instanceId, 'stopping');
    this.emit(instanceId, 'info', 'Stopping Minecraft');
    session.abort.abort();

    if (session.child?.pid) {
      await killProcessTree(session.child).catch((error) => {
        void this.logger?.warn('launch', 'Failed to kill process tree', {
          instanceId,
          error: error instanceof Error ? error.message : String(error)
        });
      });
    }

    this.sessions.delete(instanceId);
    this.setState(instanceId, 'stopped');
    this.emit(instanceId, 'info', 'Minecraft stopped');
    await this.logger?.info('launch', 'Stopped by user', { instanceId });

    setTimeout(() => {
      if (!this.sessions.has(instanceId)) {
        this.setState(instanceId, 'idle');
      }
    }, 1000);
  }

  private async appendHistory(entry: LaunchHistoryEntry): Promise<void> {
    await this.database.mutate((draft) => {
      if (!draft.launchHistory) draft.launchHistory = [];
      draft.launchHistory.push(entry);
      if (draft.launchHistory.length > MAX_HISTORY_ENTRIES) {
        draft.launchHistory = draft.launchHistory.slice(-MAX_HISTORY_ENTRIES);
      }
      const inst = draft.instances.find((i) => i.id === entry.instanceId);
      if (inst) {
        inst.launchCount = (inst.launchCount ?? 0) + 1;
      }
    });
  }

  private async finalizeHistory(
    historyId: string,
    instanceId: string,
    exitedAt: number,
    durationMs: number,
    exitCode: number | null | undefined,
    state: LaunchHistoryEntry['state']
  ): Promise<void> {
    await this.database.mutate((draft) => {
      if (!draft.launchHistory) return;
      const entry = draft.launchHistory.find((h) => h.id === historyId);
      if (entry) {
        entry.exitedAt = exitedAt;
        entry.durationMs = durationMs;
        entry.exitCode = exitCode ?? null;
        entry.state = state;
      }
      const inst = draft.instances.find((i) => i.id === instanceId);
      if (inst) {
        inst.totalPlayTimeMs = (inst.totalPlayTimeMs ?? 0) + durationMs;
      }
    });
  }

  private normalizeAccount(account: LauncherAccount): LauncherAccount {
    if (account.kind === 'offline') {
      return {
        ...account,
        accessToken: '0'
      };
    }
    if (!account.accessToken) {
      throw new Error('Microsoft session is missing an access token. Sign in again.');
    }
    return account;
  }

  private async validateCustomJava(path: string, gameVersion: string, requiredMajor: number) {
    const runtime = await this.java.inspect(path);
    if (!runtime?.valid) {
      throw new Error(`Java was not found at ${path}.`);
    }
    if (runtime.major < requiredMajor) {
      throw new Error(`Java ${requiredMajor}+ is required for Minecraft ${gameVersion}. Selected Java is ${runtime.major}.`);
    }
    return runtime;
  }

  private waitForSpawn(child: ChildProcess, instanceId: string): Promise<void> {
    return new Promise((resolve, reject) => {
      child.once('spawn', resolve);
      child.once('error', (error) => {
        this.emit(instanceId, 'error', error.message);
        reject(error);
      });
    });
  }

  private assertNotAborted(instanceId: string): void {
    if (this.sessions.get(instanceId)?.abort.signal.aborted) {
      const error = new Error('Launch cancelled');
      error.name = 'AbortError';
      throw error;
    }
  }

  private setState(instanceId: string, state: ProcessState): void {
    const session = this.sessions.get(instanceId);
    if (session) {
      session.state = state;
    }
    this.onProcessState(instanceId, state);
  }

  private emit(instanceId: string, level: ConsoleEvent['level'], message: string): void {
    for (const line of message.split(/\r?\n/).filter(Boolean)) {
      this.onConsole({
        instanceId,
        level,
        message: line,
        time: Date.now()
      });
    }
  }
}

async function killProcessTree(child: ChildProcess): Promise<void> {
  const pid = child.pid;
  if (!pid) {
    child.kill('SIGKILL');
    return;
  }

  if (process.platform === 'win32') {
    await execFileAsync('taskkill', ['/pid', String(pid), '/T', '/F']);
    return;
  }

  try {
    process.kill(-pid, 'SIGTERM');
  } catch {
    child.kill('SIGTERM');
  }

  await new Promise((resolve) => setTimeout(resolve, 1500));

  try {
    process.kill(-pid, 'SIGKILL');
  } catch {
    child.kill('SIGKILL');
  }
}

import { app, BrowserWindow, ipcMain, shell } from 'electron';
import { join } from 'node:path';
import type { DownloadProgress, LauncherAccount, LauncherSettings, MarketplaceProject, MarketplaceSearchQuery, NotificationItem, ProcessState } from '@/types/launcher';
import { MarketplaceService } from '@/api/MarketplaceService';
import { AccountService } from '@/launcher/AccountService';
import { ContentService } from '@/launcher/ContentService';
import { DownloadManager } from '@/launcher/DownloadManager';
import { InstanceService } from '@/launcher/InstanceService';
import { JavaService } from '@/launcher/JavaService';
import { JsonDatabase } from '@/launcher/JsonDatabase';
import { LauncherPaths } from '@/launcher/LauncherPaths';
import { Logger } from '@/launcher/Logger';
import { GalleryService } from '@/launcher/GalleryService';
import { PluginService } from '@/launcher/PluginService';
import { LoaderService } from '@/minecraft/LoaderService';
import { MinecraftService } from '@/minecraft/MinecraftService';
import { VersionService } from '@/minecraft/VersionService';

let mainWindow: BrowserWindow | undefined;

const paths = new LauncherPaths();
const logger = new Logger(join(app.getPath('userData'), 'logs'));
const database = new JsonDatabase(paths.databaseFile);
const downloads = new DownloadManager(logger);
const javaService = new JavaService(paths, logger);
const versionService = new VersionService(paths, downloads);
const accountService = new AccountService(database);
const instanceService = new InstanceService(database, paths);
const contentService = new ContentService(database, instanceService);
const pluginService = new PluginService(database);
const galleryService = new GalleryService(database);
const loaderService = new LoaderService(versionService, downloads, javaService, paths, instanceService);

function sendProcessState(instanceId: string, state: ProcessState): void {
  mainWindow?.webContents.send('process:state', { instanceId, state });
}

const minecraftService = new MinecraftService(
  database,
  versionService,
  loaderService,
  javaService,
  instanceService,
  accountService,
  (event) => {
    mainWindow?.webContents.send('console:event', event);
  },
  sendProcessState,
  logger
);
const marketplaceService = new MarketplaceService(database, downloads, paths, instanceService, loaderService);

function sendDownload(progress: DownloadProgress): void {
  mainWindow?.webContents.send('download:progress', progress);
}

function sendNotification(item: NotificationItem): void {
  mainWindow?.webContents.send('notification:event', item);
}

downloads.on('progress', sendDownload);

async function saveWindowBounds(): Promise<void> {
  if (!mainWindow || mainWindow.isMaximized() || mainWindow.isMinimized()) {
    return;
  }

  const [width, height] = mainWindow.getSize();
  await database.mutate((draft) => {
    draft.settings.windowWidth = width;
    draft.settings.windowHeight = height;
  });
}

async function createWindow(settings?: LauncherSettings): Promise<void> {
  const useCustomChrome = process.platform !== 'darwin';
  const width = Math.max(1040, settings?.windowWidth ?? 1280);
  const height = Math.max(680, settings?.windowHeight ?? 800);

  mainWindow = new BrowserWindow({
    width,
    height,
    minWidth: 1040,
    minHeight: 680,
    show: false,
    frame: !useCustomChrome,
    backgroundColor: '#080808',
    title: 'Dawn Launcher',
    titleBarStyle: process.platform === 'darwin' ? 'hiddenInset' : 'hidden',
    webPreferences: {
      preload: join(__dirname, '../preload/preload.mjs'),
      sandbox: false,
      contextIsolation: true,
      nodeIntegration: false
    }
  });

  mainWindow.on('maximize', () => mainWindow?.webContents.send('window:maximized', true));
  mainWindow.on('unmaximize', () => mainWindow?.webContents.send('window:maximized', false));
  mainWindow.on('resize', () => {
    void saveWindowBounds();
  });
  mainWindow.on('close', () => {
    void saveWindowBounds();
  });

  mainWindow.once('ready-to-show', () => {
    mainWindow?.show();
  });

  if (process.env.ELECTRON_RENDERER_URL) {
    await mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
  } else {
    await mainWindow.loadFile(join(__dirname, '../renderer/index.html'));
  }
}

function registerIpc(): void {
  ipcMain.handle('app:version', () => app.getVersion());
  ipcMain.handle('app:platform', () => process.platform);
  ipcMain.handle('app:openExternal', async (_event, url: string) => shell.openExternal(url));
  ipcMain.handle('app:revealPath', async (_event, path: string) => shell.showItemInFolder(path));

  ipcMain.handle('window:minimize', () => mainWindow?.minimize());
  ipcMain.handle('window:maximize', () => mainWindow?.maximize());
  ipcMain.handle('window:unmaximize', () => mainWindow?.unmaximize());
  ipcMain.handle('window:toggleMaximize', () => {
    if (!mainWindow) {
      return;
    }
    if (mainWindow.isMaximized()) {
      mainWindow.unmaximize();
    } else {
      mainWindow.maximize();
    }
  });
  ipcMain.handle('window:close', () => mainWindow?.close());
  ipcMain.handle('window:isMaximized', () => mainWindow?.isMaximized() ?? false);

  ipcMain.handle('settings:get', async () => (await database.read()).settings);
  ipcMain.handle('settings:update', async (_event, input: Partial<LauncherSettings>) => {
    const settings = await database.mutate((draft) => {
      draft.settings = { ...draft.settings, ...input };
      return draft.settings;
    });
    logger.setDebugMode(Boolean(settings.experimentalFeatures));
    await instanceService.ensureRoots(settings);
    return settings;
  });

  ipcMain.handle('accounts:list', () => accountService.list());
  ipcMain.handle('accounts:addOffline', (_event, username: string) => accountService.addOffline(username));
  ipcMain.handle('accounts:remove', (_event, id: string) => accountService.remove(id));
  ipcMain.handle('accounts:select', (_event, id: string) => accountService.select(id));
  ipcMain.handle('accounts:microsoftStart', () => accountService.microsoftStart());
  ipcMain.handle('accounts:microsoftPoll', () => accountService.microsoftPoll());
  ipcMain.handle('accounts:microsoftComplete', () => accountService.microsoftComplete());
  ipcMain.handle('accounts:ensureSession', (_event, account: LauncherAccount) => accountService.ensureValidSession(account));

  ipcMain.handle('instances:list', () => instanceService.list());
  ipcMain.handle('instances:create', (_event, input) => instanceService.create(input));
  ipcMain.handle('instances:update', (_event, id: string, input) => instanceService.update(id, input));
