}

import { Search, Tags } from 'lucide-react';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { Button } from '@/components/Button';
import { ContentTable } from '@/components/ContentTable';
import { MarketplaceGrid } from '@/components/MarketplaceGrid';
import { PageShell } from '@/components/PageShell';
import { Panel } from '@/components/Panel';
import type { ContentKind, MarketplaceProject } from '@/types/launcher';
import { useLauncherStore } from '@/store/useLauncherStore';

import modsBg from '../../backgrounds/mod.png';
import shaderBg from '../../backgrounds/shader.png';
import modpackBg from '../../backgrounds/mod.png';
import resourceBg from '../../backgrounds/background2.png';

const sectionBg: Record<ContentKind, string> = {
  mod: modsBg,
  shader: shaderBg,
  modpack: modpackBg,
  resourcepack: resourceBg
};

const sectionDescription: Record<ContentKind, string> = {
  mod: 'Browse, install, and manage mods for your instances via Modrinth and CurseForge.',
  shader: 'Browse and install shader packs to elevate your Minecraft visuals.',
  modpack: 'Discover and install curated modpacks from Modrinth and CurseForge.',
  resourcepack: 'Find and install resource packs to customize your game textures and sounds.'
};

interface LibraryPageProps {
  kind: ContentKind;
  title: string;
}

export function LibraryPage({ kind, title }: LibraryPageProps) {
  const selectedInstanceId = useLauncherStore((state) => state.selectedInstanceId);
  const instances = useLauncherStore((state) => state.instances);
  const versions = useLauncherStore((state) => state.versions);
  const query = useLauncherStore((state) => state.librarySearch);
  const librarySearchNonce = useLauncherStore((state) => state.librarySearchNonce);
  const setQuery = useLauncherStore((state) => state.setLibrarySearch);
  const searchMarketplace = useLauncherStore((state) => state.searchMarketplace);
  const installProject = useLauncherStore((state) => state.installProject);
  const selected = instances.find((instance) => instance.id === selectedInstanceId);
  const [provider, setProvider] = useState<'modrinth' | 'curseforge'>('modrinth');
  const [versionFilter, setVersionFilter] = useState(selected?.gameVersion ?? '');
  const [projects, setProjects] = useState<MarketplaceProject[]>([]);
  const [searching, setSearching] = useState(false);

  const versionOptions = useMemo(() => {
    const values = new Set<string>([selected?.gameVersion ?? '', ...versions.slice(0, 80)]);
    return [...values].filter(Boolean);
  }, [selected?.gameVersion, versions]);

  useEffect(() => {
    setVersionFilter(selected?.gameVersion ?? '');
    setProjects([]);
  }, [kind, selected?.gameVersion, selectedInstanceId]);

  const runSearch = useCallback(async () => {
    if (!query.trim()) {
      setProjects([]);
      return;
    }
    setSearching(true);
    try {
      const results = await searchMarketplace({
        provider,
        query: query.trim(),
        kind,
        gameVersion: versionFilter || selected?.gameVersion,
        loader: selected?.loader,
        limit: 24
      });
      setProjects(results.filter((project) => project.projectType === kind));
    } finally {
      setSearching(false);
    }
  }, [provider, query, kind, versionFilter, selected?.gameVersion, selected?.loader, searchMarketplace]);

  useEffect(() => {
    if (librarySearchNonce > 0) {
      void runSearch();
    }
  }, [librarySearchNonce, runSearch]);

  useEffect(() => {
    if (!query.trim()) {
      setProjects([]);
      return;
    }
    const timer = setTimeout(() => {
      void runSearch();
    }, 350);
    return () => clearTimeout(timer);
  }, [query, provider, versionFilter, kind, selected?.gameVersion, selected?.loader, runSearch]);

  const bg = sectionBg[kind];

  const main = (
    <>
      <Panel className="relative mb-4 overflow-hidden" style={{ minHeight: 140 }}>
        <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${bg})` }} />
        <div className="absolute inset-0 bg-gradient-to-r from-black/90 via-black/70 to-black/40" />
        <div className="relative z-10 flex h-full flex-col justify-between p-5" style={{ minHeight: 140 }}>
          <div>
            <h2 className="text-3xl font-black tracking-normal">{title}</h2>
            <p className="mt-1 max-w-lg text-sm text-zinc-300">{sectionDescription[kind]}</p>
            {selected && (
              <p className="mt-1.5 text-xs text-zinc-400">
                Instance: <span className="text-white font-semibold">{selected.name}</span>
                {' '}· {selected.gameVersion} · {selected.loader}
              </p>
            )}
          </div>
          {!selected && (
            <p className="mt-2 text-sm text-yellow-300/80">
              Select an instance in Instances to install content.
            </p>
          )}
        </div>
      </Panel>

      <div className="mb-4 flex flex-wrap items-center gap-2">
        <select
          value={provider}
          onChange={(event) => setProvider(event.target.value as 'modrinth' | 'curseforge')}
          className="ui-input h-10 px-3 text-sm"
        >
          <option value="modrinth">Modrinth</option>
          <option value="curseforge">CurseForge</option>
        </select>
        {versionOptions.length > 0 && (
          <label className="relative">
            <Tags size={15} className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" />
            <select
              value={versionFilter}
              onChange={(event) => setVersionFilter(event.target.value)}
              className="ui-input h-10 w-40 pl-9 pr-3 text-sm"
            >
              {versionOptions.map((version) => (
                <option key={version} value={version}>
                  {version}
                </option>
              ))}
            </select>
          </label>
        )}
        <input
          value={query}
          onChange={(event) => setQuery(event.target.value)}
          onKeyDown={(event) => event.key === 'Enter' && void runSearch()}
          className="ui-input h-10 min-w-[14rem] flex-1 px-3 text-sm"
          placeholder={`Search ${title.toLowerCase()}…`}
        />
        <Button tone="primary" icon={<Search size={16} />} onClick={() => void runSearch()} disabled={searching}>
          {searching ? 'Searching…' : 'Search'}
        </Button>
      </div>

      {projects.length > 0 ? (
        <MarketplaceGrid
          projects={projects}
          instanceId={selectedInstanceId}
          onInstall={(project) => selectedInstanceId && void installProject(project, selectedInstanceId)}
        />
      ) : (
        <Panel className="p-8 text-center text-zinc-500">
          {query.trim()
            ? 'No results found. Try a different query or switch providers.'
            : `Search Modrinth or CurseForge to find and install ${title.toLowerCase()} into the selected instance.`}
        </Panel>
      )}
    </>
  );

  return (
    <PageShell aside={<ContentTable instanceId={selectedInstanceId} kind={kind} query={query} />} asideWidth={420}>
      {main}
    </PageShell>
  );
}

import { ExternalLink, KeyRound, LogIn, Shield, Trash2, UserPlus } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';
import { Button } from '@/components/Button';
import { PageShell } from '@/components/PageShell';
import { Panel } from '@/components/Panel';
import type { DeviceCodeStart } from '@/types/launcher';
import { useLauncherStore } from '@/store/useLauncherStore';

import accountsBg from '../../backgrounds/accounts.png';

export function AccountPage() {
  const accounts = useLauncherStore((state) => state.accounts);
  const settings = useLauncherStore((state) => state.settings);
  const selectedAccountId = useLauncherStore((state) => state.selectedAccountId);
  const setSelectedAccount = useLauncherStore((state) => state.setSelectedAccount);
  const addOfflineAccount = useLauncherStore((state) => state.addOfflineAccount);
  const startMicrosoftLogin = useLauncherStore((state) => state.startMicrosoftLogin);
  const refresh = useLauncherStore((state) => state.refresh);
  const librarySearch = useLauncherStore((state) => state.librarySearch);
  const visibleAccounts = accounts.filter(
    (account) => !librarySearch.trim() || account.username.toLowerCase().includes(librarySearch.trim().toLowerCase())
  );
  const [offlineName, setOfflineName] = useState('');
  const [deviceStart, setDeviceStart] = useState<DeviceCodeStart>();
  const [authError, setAuthError] = useState('');
  const [polling, setPolling] = useState(false);
  const pollTimer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);

  const startLogin = async () => {
    setAuthError('');
    try {
      const start = await startMicrosoftLogin();
      setDeviceStart(start);
      await window.dawn.app.openExternal(start.verificationUri);
    } catch (error) {
      setAuthError(error instanceof Error ? error.message : String(error));
    }
  };

  useEffect(() => {
    if (!deviceStart) {
      return;
    }

    let cancelled = false;
    setPolling(true);

    const poll = async () => {
      while (!cancelled) {
        const result = await window.dawn.accounts.microsoftPoll();
        if (result.status === 'complete') {
          setDeviceStart(undefined);
          setPolling(false);
          await refresh();
          return;
        }
        if (result.status === 'expired') {
          setAuthError('Microsoft login expired. Start a new login.');
          setDeviceStart(undefined);
          setPolling(false);
          return;
        }
        if (result.status === 'error') {
          setAuthError(result.message);
          setDeviceStart(undefined);
          setPolling(false);
          return;
        }
        const waitMs = 'interval' in result ? result.interval * 1000 : deviceStart.interval * 1000;
        await new Promise<void>((resolve) => {
          pollTimer.current = setTimeout(resolve, waitMs);
        });
      }
    };

    void poll();

    return () => {
      cancelled = true;
      if (pollTimer.current) {
        clearTimeout(pollTimer.current);
      }
      setPolling(false);
    };
  }, [deviceStart, refresh]);

  const authAside = (
    <>
      <Panel className="p-5">
        <div className="flex items-center gap-2.5 mb-4">
          <div className="grid h-8 w-8 place-items-center rounded-lg bg-[color-mix(in_srgb,var(--accent)_15%,transparent)] text-accent">
            <LogIn size={16} />
          </div>
          <h3 className="font-black">Microsoft Account</h3>
        </div>
        <div className="grid gap-3">
          <p className="text-xs text-muted leading-relaxed">
            Sign in with your Microsoft account to play the official Minecraft version. Requires a valid Minecraft Java Edition license.
          </p>
          <Button icon={<KeyRound size={16} />} onClick={() => void startLogin()} disabled={polling}>
            {polling ? 'Waiting for approval…' : 'Start Microsoft Login'}
          </Button>
          {!settings?.microsoftClientId && (
            <p className="rounded-lg border border-yellow-400/20 bg-yellow-400/10 p-3 text-xs text-yellow-100">
              Add a Microsoft public client ID in Settings → Credentials to enable Microsoft login.
            </p>
          )}
          {deviceStart && (
            <div className="rounded-lg border border-white/10 bg-black/30 p-4 text-sm text-zinc-300">
              <p className="text-xs uppercase tracking-wider text-zinc-500">Authorization Code</p>
              <p className="mt-1.5 text-3xl font-black tracking-widest text-white">{deviceStart.userCode}</p>
              <p className="mt-2 break-all text-xs text-zinc-400">{deviceStart.verificationUri}</p>
              <p className="mt-3 text-xs text-zinc-500">
                {polling ? '⏳ Waiting for browser approval…' : 'Open the link above and enter the code.'}
              </p>
              <Button className="mt-3 w-full" icon={<ExternalLink size={16} />} onClick={() => void window.dawn.app.openExternal(deviceStart.verificationUri)}>
                Open Browser
              </Button>
            </div>
          )}
          {authError && (
            <p className="rounded-lg border border-red-400/20 bg-red-400/10 p-3 text-xs text-red-100">{authError}</p>
          )}
        </div>
      </Panel>

      <Panel className="p-5 mt-4">
        <div className="flex items-center gap-2.5 mb-4">
          <div className="grid h-8 w-8 place-items-center rounded-lg bg-[color-mix(in_srgb,var(--accent)_15%,transparent)] text-accent">
            <UserPlus size={16} />
          </div>
          <h3 className="font-black">Offline Account</h3>
        </div>
        <p className="mb-3 text-xs text-muted leading-relaxed">
          Play without a Microsoft account. Offline mode works on servers with online-mode disabled.
        </p>
        <div className="flex gap-2">
          <input
            value={offlineName}
            onChange={(event) => setOfflineName(event.target.value)}
            onKeyDown={(event) => {
              if (event.key === 'Enter' && offlineName.trim()) {
                void addOfflineAccount(offlineName.trim()).then(() => setOfflineName(''));
              }
            }}
            className="ui-input h-10 min-w-0 flex-1 px-3"
            placeholder="Enter username"
          />
          <Button
            tone="primary"
            disabled={!offlineName.trim()}
            onClick={() => void addOfflineAccount(offlineName.trim()).then(() => setOfflineName(''))}
          >
            Add
          </Button>
        </div>
      </Panel>
    </>
  );

  return (
    <PageShell aside={authAside} asideWidth={380}>
      <Panel className="relative mb-5 overflow-hidden" style={{ minHeight: 130 }}>
        <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${accountsBg})` }} />
        <div className="absolute inset-0 bg-gradient-to-r from-black/90 via-black/70 to-black/40" />
        <div className="relative z-10 p-5" style={{ minHeight: 130 }}>
          <h2 className="text-3xl font-black tracking-normal">Accounts</h2>
          <p className="mt-1 max-w-lg text-sm text-zinc-300">
            Manage Microsoft and offline profiles for launching Minecraft.
          </p>
          <div className="mt-2 flex items-center gap-2 text-xs text-zinc-400">
            <Shield size={13} />
            <span>{accounts.length} account{accounts.length !== 1 ? 's' : ''} configured</span>
          </div>
        </div>
      </Panel>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
        {visibleAccounts.map((account) => (
          <Panel key={account.id} className="p-5">
            <div className="flex items-center gap-4">
              <div className="grid h-16 w-16 shrink-0 place-items-center overflow-hidden rounded-xl bg-[color-mix(in_srgb,var(--accent)_12%,transparent)] border border-subtle">
                {account.avatarUrl
                  ? <img src={account.avatarUrl} alt={account.username} className="h-full w-full object-cover" />
                  : <span className="text-3xl font-black text-accent">{account.username[0]?.toUpperCase()}</span>
                }
              </div>
              <div className="min-w-0 flex-1">
                <h3 className="truncate text-lg font-black">{account.username}</h3>
                <p className="text-sm text-muted capitalize">{account.kind} account</p>
                <p className="mt-0.5 truncate text-xs text-muted opacity-60">{account.uuid}</p>
              </div>
              {account.id === selectedAccountId && (
                <span className="shrink-0 rounded-full bg-emerald-500/15 border border-emerald-400/25 px-2.5 py-1 text-xs font-semibold text-emerald-300">
                  Active
                </span>
              )}
            </div>
            <div className="mt-4 flex gap-2">
              <Button
                className="flex-1"
                tone={account.id === selectedAccountId ? 'primary' : 'secondary'}
                onClick={() => void setSelectedAccount(account.id)}
              >
                {account.id === selectedAccountId ? 'Selected' : 'Select'}
              </Button>
              <Button
                tone="danger"
                icon={<Trash2 size={15} />}
                onClick={() => void window.dawn.accounts.remove(account.id).then(refresh)}
              >
                Remove
              </Button>
            </div>
          </Panel>
        ))}
        {!visibleAccounts.length && (
          <Panel className="p-8 text-center text-sm text-muted lg:col-span-2">
            {accounts.length
              ? 'No accounts match your search.'
              : 'No accounts added. Add a Microsoft or offline account to get started.'}
          </Panel>
        )}
      </div>
    </PageShell>
  );
}

import { Camera, FolderOpen, RotateCw } from 'lucide-react';
import { useCallback, useEffect, useState } from 'react';
import { Button } from '@/components/Button';
import { PageShell } from '@/components/PageShell';
import { Panel } from '@/components/Panel';
import type { ScreenshotItem } from '@/types/launcher';
import { useLauncherStore } from '@/store/useLauncherStore';

import galleryBg from '../../backgrounds/background2.png';

function ScreenshotCard({ screenshot }: { screenshot: ScreenshotItem }) {
  const [url, setUrl] = useState('');
  const [missing, setMissing] = useState(false);

  useEffect(() => {
    let cancelled = false;
    void window.dawn.gallery.preview(screenshot.path).then((preview) => {
      if (cancelled) return;
      if (!preview) {
        setMissing(true);
        return;
      }
      setUrl(preview);
    });
    return () => {
      cancelled = true;
    };
  }, [screenshot.path]);

  return (
    <Panel className="overflow-hidden transition hover:border-accent/30">
      <button type="button" className="block w-full" onClick={() => void window.dawn.app.revealPath(screenshot.path)}>
        {url && !missing ? (
          <img src={url} alt={screenshot.name} className="aspect-video w-full object-cover" />
        ) : (
          <div className="grid aspect-video place-items-center bg-white/[0.04] text-xs text-zinc-500">
            {missing ? 'File missing' : 'Loading…'}
          </div>
        )}
        <div className="flex items-center justify-between gap-3 p-3 text-left">
          <span className="min-w-0 truncate text-sm font-semibold">{screenshot.name}</span>
          <span className="shrink-0 text-xs text-zinc-500">
            {new Date(screenshot.createdAt).toLocaleDateString()}
          </span>
        </div>
      </button>
    </Panel>
  );
}

export function GalleryPage() {
  const instances = useLauncherStore((state) => state.instances);
  const selectedInstanceId = useLauncherStore((state) => state.selectedInstanceId);
  const selected = instances.find((instance) => instance.id === selectedInstanceId);
  const [screenshots, setScreenshots] = useState<ScreenshotItem[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const librarySearch = useLauncherStore((state) => state.librarySearch);
  const visibleScreenshots = screenshots.filter(
    (shot) => !librarySearch.trim() || shot.name.toLowerCase().includes(librarySearch.trim().toLowerCase())
  );

  const refresh = useCallback(async () => {
    if (!selectedInstanceId) {
      setScreenshots([]);
      return;
    }
    setIsRefreshing(true);
    try {
      setScreenshots(await window.dawn.gallery.list(selectedInstanceId));
    } finally {
      setIsRefreshing(false);
    }
  }, [selectedInstanceId]);

  useEffect(() => {
    if (!selectedInstanceId) {
      setScreenshots([]);
      return;
    }

    void refresh();
    void window.dawn.gallery.watch(selectedInstanceId);
    const unsubscribe = window.dawn.events.onGalleryChanged((instanceId) => {
      if (instanceId === selectedInstanceId) {
        void refresh();
      }
    });

    return () => {
      unsubscribe();
      void window.dawn.gallery.unwatch(selectedInstanceId);
    };
  }, [selectedInstanceId, refresh]);

  return (
    <PageShell>
      <Panel className="relative mb-5 overflow-hidden" style={{ minHeight: 130 }}>
        <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${galleryBg})` }} />
        <div className="absolute inset-0 bg-gradient-to-r from-black/90 via-black/70 to-black/40" />
        <div className="relative z-10 flex items-center justify-between gap-4 p-5" style={{ minHeight: 130 }}>
          <div>
            <h2 className="text-3xl font-black tracking-normal">Gallery</h2>
            <p className="mt-1 max-w-lg text-sm text-zinc-300">
              {selected
                ? `Screenshots for ${selected.name} — press F2 in-game to capture.`
                : 'Select an instance to browse its screenshots.'}
            </p>
            {selected && (
              <p className="mt-1.5 text-xs text-zinc-400">
                {selected.gameDir}/screenshots
              </p>
            )}
          </div>
          <div className="flex shrink-0 gap-2">
            <Button icon={<RotateCw size={16} />} onClick={() => void refresh()} disabled={isRefreshing}>
              {isRefreshing ? 'Refreshing…' : 'Refresh'}
            </Button>
            <Button
              tone="primary"
              icon={<FolderOpen size={16} />}
              onClick={() => selected && void window.dawn.gallery.openFolder(selected.id)}
              disabled={!selected}
            >
              Open Folder
            </Button>
          </div>
        </div>
      </Panel>

      {visibleScreenshots.length > 0 ? (
        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 xl:grid-cols-3">
          {visibleScreenshots.map((screenshot) => (
            <ScreenshotCard key={screenshot.path} screenshot={screenshot} />
          ))}
        </div>
      ) : (
        <Panel className="grid aspect-video place-items-center border-dashed text-center text-zinc-500 max-h-64">
          <div>
            <Camera size={36} className="mx-auto mb-3 opacity-40" />
            <p className="font-semibold">No screenshots found</p>
            <p className="mt-1 text-sm">
              {selected
                ? 'Press F2 while in-game to take a screenshot.'
                : 'Select an instance from the sidebar first.'}
            </p>
          </div>
        </Panel>
      )}
    </PageShell>
  );
}

import { Cpu, FolderOpen, Palette, PlugZap, RefreshCcw, Save, Trash2 } from 'lucide-react';
import { useEffect, useState } from 'react';
import { Button } from '@/components/Button';
import { PageShell } from '@/components/PageShell';
import { Panel } from '@/components/Panel';
import type { LauncherSettings, PluginManifest } from '@/types/launcher';
import { useLauncherStore } from '@/store/useLauncherStore';
import { cn } from '@/utils/cn';

const themeAccents: Record<LauncherSettings['theme'], string> = {
  ember: '#ff7a1a',
  midnight: '#38bdf8',
  dark: '#a3e635',
  light: '#ff7a1a',
  custom: '#ff7a1a'
};

type SettingsSection = 'appearance' | 'runtime' | 'credentials' | 'java' | 'plugins' | 'history';

const sections: Array<{ id: SettingsSection; label: string }> = [
  { id: 'appearance', label: 'Appearance' },
  { id: 'runtime', label: 'Minecraft Runtime' },
  { id: 'credentials', label: 'Credentials' },
  { id: 'java', label: 'Java Runtimes' },
  { id: 'plugins', label: 'Plugins' },
  { id: 'history', label: 'Launch History' }
];

export function SettingsPage() {
  const settings = useLauncherStore((state) => state.settings);
  const javaRuntimes = useLauncherStore((state) => state.javaRuntimes);
  const launchHistory = useLauncherStore((state) => state.launchHistory);
  const saveSettings = useLauncherStore((state) => state.saveSettings);
  const scanJava = useLauncherStore((state) => state.scanJava);
  const clearHistory = useLauncherStore((state) => state.clearHistory);
  const [draft, setDraft] = useState<Partial<LauncherSettings>>({});
  const [plugins, setPlugins] = useState<PluginManifest[]>([]);
  const [section, setSection] = useState<SettingsSection>('appearance');
  const [clearConfirm, setClearConfirm] = useState(false);
  const librarySearch = useLauncherStore((state) => state.librarySearch);
  const visibleSections = sections.filter(
    (item) => !librarySearch.trim() || item.label.toLowerCase().includes(librarySearch.trim().toLowerCase())
  );

  useEffect(() => {
    setDraft(settings ?? {});
  }, [settings]);

  useEffect(() => {
    void window.dawn.plugins.list().then(setPlugins);
  }, []);

  const update = <K extends keyof LauncherSettings>(key: K, value: LauncherSettings[K]) =>
    setDraft((current) => ({ ...current, [key]: value }));

  const totalPlayMs = launchHistory.reduce((sum, h) => sum + (h.durationMs ?? 0), 0);

  function formatDuration(ms: number) {
    if (!ms) return '0m';
    const mins = Math.floor(ms / 60000);
    const hrs = Math.floor(mins / 60);
    const remainMins = mins % 60;
    if (hrs === 0) return `${remainMins}m`;
    if (remainMins === 0) return `${hrs}h`;
    return `${hrs}h ${remainMins}m`;
  }

  return (
    <div className="flex h-full min-h-0 flex-col overflow-hidden">
      <div className="mb-4 flex shrink-0 flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-3xl font-black tracking-normal">Settings</h2>
          <p className="mt-1 text-sm text-zinc-400">Runtime, downloads, accounts, and appearance.</p>
        </div>
        <Button tone="primary" icon={<Save size={16} />} onClick={() => void saveSettings(draft)}>
          Save Changes
        </Button>
      </div>

      <div className="grid min-h-0 flex-1 grid-cols-1 gap-5 overflow-hidden lg:grid-cols-[220px_minmax(0,1fr)]">
        <nav className="flex min-h-0 flex-col gap-1 overflow-y-auto overscroll-contain rounded-lg border border-subtle bg-black/20 p-2 lg:max-h-full">
          {visibleSections.map((item) => (
            <button
              key={item.id}
              type="button"
              onClick={() => setSection(item.id)}
              className={cn(
                'rounded-md px-3 py-2.5 text-left text-sm font-semibold text-zinc-400 transition hover:bg-white/[0.08] hover:text-white',
                section === item.id && 'bg-white/[0.1] text-white accent-ring'
              )}
            >
              {item.label}
            </button>
          ))}
          <div className="mt-auto hidden pt-2 lg:block">
            <Button
              className="w-full"
              icon={<FolderOpen size={16} />}
              onClick={() => draft.minecraftRoot && void window.dawn.app.revealPath(draft.minecraftRoot)}
              disabled={!draft.minecraftRoot}
            >
              Reveal Root
            </Button>
          </div>
        </nav>

        <PageShell>
          {section === 'appearance' && (
            <Panel className="p-5">
              <div className="mb-4 flex items-center gap-2">
                <Palette size={18} className="text-accent" />
                <h3 className="font-black">Theme & Appearance</h3>
              </div>
              <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Accent Color</span>
                  <input
                    type="color"
                    value={draft.accentColor ?? '#ff7a1a'}
                    onChange={(event) => update('accentColor', event.target.value)}
                    className="h-10 w-full rounded-md border border-subtle bg-black/30 p-1 cursor-pointer"
                  />
                </label>
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Theme</span>
                  <select
                    value={draft.theme ?? 'ember'}
                    onChange={(event) => {
                      const theme = event.target.value as LauncherSettings['theme'];
                      setDraft((current) => ({
                        ...current,
                        theme,
                        accentColor: themeAccents[theme]
                      }));
                    }}
                    className="ui-input h-10 px-3"
                  >
                    <option value="ember">Ember</option>
                    <option value="midnight">Midnight</option>
                    <option value="dark">Dark</option>
                    <option value="light">Light</option>
                    <option value="custom">Custom</option>
                  </select>
                </label>
                <div className="grid grid-cols-3 gap-2 md:col-span-2 sm:grid-cols-5">
                  {(['ember', 'midnight', 'dark', 'light', 'custom'] as const).map((theme) => (
                    <button
                      key={theme}
                      type="button"
                      onClick={() => setDraft((current) => ({ ...current, theme, accentColor: themeAccents[theme] }))}
                      className={cn(
                        'h-10 rounded-md border text-sm font-semibold capitalize transition',
                        draft.theme === theme
                          ? 'border-accent/50 bg-[color-mix(in_srgb,var(--accent)_15%,transparent)] text-white'
                          : 'border-subtle bg-surface-muted text-muted hover:bg-surface-hover hover:text-primary'
                      )}
                    >
                      {theme}
                    </button>
                  ))}
                </div>
                {draft.theme === 'custom' && (
                  <label className="grid gap-2 text-sm md:col-span-2">
                    <span className="text-zinc-400">Custom CSS Variables</span>
                    <textarea
                      value={draft.customThemeCss ?? ''}
                      onChange={(event) => update('customThemeCss', event.target.value)}
                      className="ui-input min-h-28 p-3 font-mono text-xs"
                      placeholder=":root { --page-bg: #0a0a0a; }"
                    />
                  </label>
                )}
              </div>
            </Panel>
          )}

          {section === 'runtime' && (
            <Panel className="p-5">
              <div className="mb-4 flex items-center gap-2">
                <Cpu size={18} className="text-accent" />
                <h3 className="font-black">Minecraft Runtime</h3>
              </div>
              <div className="grid gap-4">
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Default RAM: <strong className="text-primary">{(draft.defaultRamMb ?? 4096).toLocaleString()} MB</strong></span>
                  <input
                    className="range"
                    type="range"
                    min={1024}
                    max={24576}
                    step={512}
                    value={draft.defaultRamMb ?? 4096}
                    onChange={(event) => update('defaultRamMb', Number(event.target.value))}
                  />
                  <div className="flex justify-between text-xs text-muted">
                    <span>1 GB</span>
                    <span>24 GB</span>
                  </div>
                </label>
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Java Executable Path</span>
                  <input
                    value={draft.javaPath ?? ''}
                    onChange={(event) => update('javaPath', event.target.value || undefined)}
                    className="ui-input h-10 px-3"
                    placeholder="Auto-detect (recommended)"
                  />
                </label>
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Minecraft Root Directory</span>
                  <input
                    value={draft.minecraftRoot ?? ''}
                    onChange={(event) => update('minecraftRoot', event.target.value || undefined)}
                    className="ui-input h-10 px-3"
                    placeholder="Default app data directory"
                  />
                </label>
                <label className="flex cursor-pointer items-center justify-between rounded-lg border border-subtle bg-surface-muted px-4 py-3 text-sm transition hover:bg-surface-hover">
                  <span>Performance Mode</span>
                  <input
                    type="checkbox"
                    checked={draft.performanceMode ?? false}
                    onChange={(event) => update('performanceMode', event.target.checked)}
                    className="accent-[var(--accent)] h-4 w-4"
                  />
                </label>
                <label className="flex cursor-pointer items-center justify-between rounded-lg border border-subtle bg-surface-muted px-4 py-3 text-sm transition hover:bg-surface-hover">
                  <span>Discord Rich Presence</span>
                  <input
                    type="checkbox"
                    checked={draft.discordRpc ?? true}
                    onChange={(event) => update('discordRpc', event.target.checked)}
                    className="accent-[var(--accent)] h-4 w-4"
                  />
                </label>
              </div>
            </Panel>
          )}

          {section === 'credentials' && (
            <Panel className="p-5">
              <h3 className="mb-4 font-black">Credentials & API Keys</h3>
              <div className="grid gap-4">
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">Microsoft Azure Public Client ID</span>
                  <input
                    value={draft.microsoftClientId ?? ''}
                    onChange={(event) => update('microsoftClientId', event.target.value || undefined)}
                    className="ui-input h-10 px-3 font-mono text-sm"
                    placeholder="xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
                  />
                  <p className="text-xs text-muted">Required for Microsoft account login. Create a public client app in Azure Portal.</p>
                </label>
                <label className="grid gap-2 text-sm">
                  <span className="text-zinc-400">CurseForge API Key</span>
                  <input
                    value={draft.curseForgeApiKey ?? ''}
                    onChange={(event) => update('curseForgeApiKey', event.target.value || undefined)}
                    className="ui-input h-10 px-3"
                    placeholder="$2a$10$…"
                  />
                  <p className="text-xs text-muted">Required to search and install mods from CurseForge.</p>
                </label>
                <label className="flex cursor-pointer items-center justify-between rounded-lg border border-subtle bg-surface-muted px-4 py-3 text-sm transition hover:bg-surface-hover">
                  <div>
                    <p>Experimental Features</p>
                    <p className="text-xs text-muted mt-0.5">Enable debug logging and unstable features.</p>
                  </div>
                  <input
                    type="checkbox"
                    checked={draft.experimentalFeatures ?? false}
                    onChange={(event) => update('experimentalFeatures', event.target.checked)}
                    className="accent-[var(--accent)] h-4 w-4"
                  />
                </label>
              </div>
            </Panel>
          )}

          {section === 'java' && (
            <Panel className="p-5">
              <div className="mb-4 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Cpu size={18} className="text-accent" />
                  <h3 className="font-black">Java Runtimes</h3>
                </div>
                <Button icon={<RefreshCcw size={15} />} onClick={() => void scanJava()}>
                  Scan Again
                </Button>
              </div>
              <div className="grid gap-3">
                {javaRuntimes.map((runtime) => (
                  <button
                    key={runtime.path}
                    type="button"
                    onClick={() => update('javaPath', runtime.path)}
                    className={cn(
                      'w-full min-w-0 overflow-hidden rounded-lg border p-3.5 text-left transition',
                      draft.javaPath === runtime.path
                        ? 'border-accent/40 bg-[color-mix(in_srgb,var(--accent)_10%,transparent)]'
                        : 'border-subtle bg-surface-muted hover:bg-surface-hover'
                    )}
                  >
                    <div className="flex items-center justify-between gap-3">
                      <p className="font-semibold">Java {runtime.major}</p>
                      <div className="flex items-center gap-2">
                        {runtime.vendor && <span className="text-xs text-muted">{runtime.vendor}</span>}
                        {runtime.arch && <span className="rounded bg-surface-muted px-1.5 py-0.5 text-xs text-muted">{runtime.arch}</span>}
                        <span className={cn('rounded px-1.5 py-0.5 text-xs font-medium', runtime.valid ? 'bg-emerald-500/10 text-emerald-300' : 'bg-red-500/10 text-red-300')}>
                          {runtime.valid ? 'Valid' : 'Invalid'}
                        </span>
                      </div>
                    </div>
                    <p className="mt-1 truncate text-xs text-muted">{runtime.path}</p>
                    <p className="mt-0.5 text-xs text-muted opacity-60">{runtime.version}</p>
                  </button>
                ))}
                {!javaRuntimes.length && (
                  <div className="rounded-lg border border-subtle bg-surface-muted p-5 text-center text-sm text-muted">
                    <p>No Java runtimes detected.</p>
                    <p className="mt-1 text-xs">Install Java 17 or later and click Scan Again.</p>
                  </div>
                )}
              </div>
            </Panel>
          )}

          {section === 'plugins' && (
            <Panel className="p-5">
              <div className="mb-4 flex items-center gap-2">
                <PlugZap size={18} className="text-accent" />
                <h3 className="font-black">Plugins</h3>
              </div>
              <div className="grid gap-3">
                {plugins.map((plugin) => (
                  <button
                    key={plugin.id}
                    type="button"
                    onClick={() => void window.dawn.plugins.toggle(plugin.id).then(setPlugins)}
                    className="flex items-center justify-between rounded-lg border border-subtle bg-surface-muted px-4 py-3 text-left transition hover:bg-surface-hover"
                  >
                    <div className="min-w-0">
                      <span className="block min-w-0 truncate text-sm font-semibold">{plugin.name}</span>
                      <span className="text-xs text-muted">v{plugin.version}</span>
                    </div>
                    <span className={cn(
                      'shrink-0 rounded-full px-2.5 py-1 text-xs font-semibold',
                      plugin.enabled
                        ? 'bg-emerald-500/15 text-emerald-300'
                        : 'bg-surface-muted text-muted'
                    )}>
                      {plugin.enabled ? 'Enabled' : 'Disabled'}
                    </span>
                  </button>
                ))}
                {!plugins.length && (
                  <p className="text-sm text-muted">No plugins installed.</p>
                )}
              </div>
            </Panel>
          )}

          {section === 'history' && (
            <Panel className="p-5">
              <div className="mb-4 flex items-center justify-between">
                <h3 className="font-black">Launch History</h3>
                {launchHistory.length > 0 && (
                  <Button
                    tone="danger"
                    icon={<Trash2 size={15} />}
                    onClick={() => {
                      if (clearConfirm) {
                        void clearHistory();
                        setClearConfirm(false);
                      } else {
                        setClearConfirm(true);
                        setTimeout(() => setClearConfirm(false), 3000);
                      }
                    }}
                  >
                    {clearConfirm ? 'Confirm Clear' : 'Clear History'}
                  </Button>
                )}
              </div>
              <div className="mb-4 grid grid-cols-2 gap-3 sm:grid-cols-3">
                <div className="rounded-lg border border-subtle bg-surface-muted p-3 text-center">
                  <p className="text-2xl font-black">{launchHistory.length}</p>
                  <p className="mt-0.5 text-xs text-muted">Total Sessions</p>
                </div>
                <div className="rounded-lg border border-subtle bg-surface-muted p-3 text-center">
                  <p className="text-2xl font-black">{formatDuration(totalPlayMs)}</p>
                  <p className="mt-0.5 text-xs text-muted">Total Play Time</p>
                </div>
                <div className="rounded-lg border border-subtle bg-surface-muted p-3 text-center sm:col-span-1 col-span-2">
                  <p className="text-2xl font-black">
                    {launchHistory.filter(h => h.state === 'crashed').length}
                  </p>
                  <p className="mt-0.5 text-xs text-muted">Crashes</p>
                </div>
              </div>
              {launchHistory.length > 0 ? (
                <div className="max-h-96 space-y-1.5 overflow-y-auto overscroll-contain pr-1">
                  {launchHistory.slice(0, 50).map((entry) => (
                    <div
                      key={entry.id}
                      className="flex min-w-0 items-center gap-3 rounded-md border border-subtle bg-surface-muted px-3 py-2.5"
                    >
                      <div className="min-w-0 flex-1">
                        <p className="truncate text-sm font-semibold">{entry.instanceName}</p>
                        <p className="text-xs text-muted">
                          {entry.gameVersion} · {entry.loader} · {entry.accountUsername}
                        </p>
                      </div>
                      <div className="shrink-0 text-right">
                        <p className="text-xs text-muted">{new Date(entry.launchedAt).toLocaleDateString()}</p>
                        {entry.durationMs != null && (
                          <p className="text-xs text-muted">{formatDuration(entry.durationMs)}</p>
                        )}
                        <span className={cn(
                          'inline-block rounded px-1.5 py-0.5 text-xs',
                          entry.state === 'exited' ? 'text-emerald-300' :
                          entry.state === 'crashed' ? 'text-red-300' :
                          'text-zinc-400'
                        )}>
                          {entry.state}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-center text-sm text-muted py-6">No launch history yet. Play some Minecraft!</p>
              )}
            </Panel>
          )}
        </PageShell>
      </div>
    </div>
  );
}
